"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["4258"],{19064(e,i,t){t.r(i),t.d(i,{default:()=>r});var s=t(74848),n=t(47643),o=JSON.parse('{"id":270,"en":{"title":"Probing Queries","prompt":"You are an expert in management, anthropology, sociology, psychology, philosophy, linguistics, cultural commentary, and psychoanalytic theory.\\n\\nFor the next part, I will give you a \\"Question X\\". Instead of answering it directly, analyze the question as follows:\\n\\n1. Assess \\"Question X\\" for quality, giving five reasons.\\n2. Improve \\"Question X\\", presenting five new versions.\\n3. Devise an answer to \\"Question X\\", detailing your thought process.\\n4. Guess why \\"Question X\\" was asked, suggesting five possible motives.\\n5. Identify five areas of knowledge the questioner might be lacking.\\n6. Infer five potential assumptions of the questioner.\\n7. Discuss these assumptions, outlining their pros, cons and impact on the questioner.\\n8. Speculate on the questioner\'s worldview and values, listing five key points.\\n9. Critique the inferred worldview and values, discussing their pros, cons and influence on the questioner.\\n10. Hypothesize about the questioner\'s self-identity.\\n11. Evaluate this self-identity, discussing its strengths, weaknesses, and impact on the questioner.\\n\\nQuestion X: [first question to deepen]","remark":"Contributed by @\u81EA\u7531\u53F6\u3002"},"tags":["contribute","mind"],"website":null,"count":1308,"related":[{"id":206,"title":"Deep thinking assistant","remark":"Provide high-quality and valuable questions based on keywords, themes, or concepts, covering various aspects of human cognition, emotions, and behaviors, in order to train one\'s ability for deep thinking. The response structure of this prompt is very clear, making it suitable for use when organizing concepts. Contributed by @MoeACG."},{"id":196,"title":"Think Tank","remark":"Provide you with various different perspectives for thinking. Contributed by @jiuwen624."},{"id":176,"title":"Question Assistant","remark":"Ask from multiple angles to trigger deep thinking. Contributed by @meishiwanwan."}],"metaTitle":"Deep Inquiry Analyst","metaDescription":"Questioning a question? Analyze intent, assumptions, and worldview behind any query. Redefine and improved questions deeply.","faq":[{"q":"How is it different from ID 176 question assistant?","a":"ID 176 only generates questions; ID 270 first assesses question quality, adds premises, then gives multi-angle analysis, a more complete structure. For one-shot deep decomposition use 270, for quick brainstorming use 176. For research topics use 270 for first-round exploration."},{"q":"Are the disciplinary perspectives (management, anthropology, etc.) the AI invokes really deep?","a":"Widely-known disciplines (psychology, sociology) get fairly deep analysis. Obscure ones (cultural criticism, psychoanalysis) often stick tags on content. For key analysis, follow up with \\"which scholars in this discipline are most relevant,\\" which quickly reveals whether the AI really knows the field."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,s.jsx)(n.A,{prompt:o,currentLanguage:"en"})}}}]);